import { task, schemaTask } from "@trigger.dev/sdk/v3";
import { ai } from "@trigger.dev/sdk/ai";
import { z } from "zod";

const trial_id = "123";

// 1. Define a schemaTask called refine-text-${trial_id}
export const refineTask = schemaTask({
  id: `refine-text-${trial_id}`,
  schema: z.object({
    text: z.string(),
  }),
  run: async (payload) => {
    // Mocked refinement logic
    return {
      refinedText: `${payload.text} (refined)`,
    };
  },
});

// 2. Wrap this task using ai.tool(refineTask)
export const refineTool = ai.tool(refineTask);

// 3. Define a parent task agent-loop-${trial_id} that uses this tool in a loop
export const agentLoopTask = task({
  id: `agent-loop-${trial_id}`,
  run: async (payload) => {
    let currentText = "Start text";

    // Refine at least twice
    for (let i = 0; i < 2; i++) {
      // In a real scenario, you might pass this tool to an LLM
      // Here we simulate the agent calling the tool via the task
      const result = await refineTask.triggerAndWait({ text: currentText });

      if (result.ok) {
        currentText = result.output.refinedText;
      } else {
        throw new Error(`Refinement failed at step ${i + 1}`);
      }
    }

    return {
      finalText: currentText,
    };
  },
});

